num_qubits = 5
results = {i: set() for i in range(num_qubits)}
for outcome, count in counts.items():
    if count > 0:
        bits = outcome.zfill(num_qubits)
        for i in range(num_qubits):
            results[num_qubits - 1 - i].add(bits[i])

deterministic_qubits = [q for q, vals in results.items() if len(vals) == 1]
probabilistic_qubits = [q for q, vals in results.items() if len(vals) > 1]

assert len(deterministic_qubits) > 0, "No deterministic qubit found"
assert len(probabilistic_qubits) > 0, "No probabilistic qubit found"
